BACKGROUND_TEX_WIDTH = 864
BACKGROUND_TEX_HEIGHT = 480
def main():
    delta_output = []
    delta_output.append(texture_background[0])
    def output_delta(d):
        nonlocal delta_output
        if d > 63 or d < -64:
            delta_output.append((d<<1)|1)
            delta_output.append(d>>7)
        else:
            delta_output.append((d<<1)|0)

            
    bits_out = []
    for y in range(BACKGROUND_TEX_HEIGHT):
        has_up = y >= 1
        start_x = 1 if y == 0 else 0
        if y > 0:
            delta_output.append((texture_background[y*BACKGROUND_TEX_WIDTH] - texture_background[(y-1)*BACKGROUND_TEX_WIDTH]))
        for x in range(1, BACKGROUND_TEX_WIDTH):
            has_left = x >= 1
            delta_left = texture_background[y*BACKGROUND_TEX_WIDTH + x] - texture_background[y*BACKGROUND_TEX_WIDTH+x-1] if has_left else 2000
            output_delta(delta_left)
        

    return delta_output #, bits_out


def lz_encode(data, window_size=64, min_match=3, max_match=8):
    """
    Compress a list of 8-bit integers.

    Returns a list of tokens:
      (0, value)          -> literal
      (offset, length)    -> back-reference
    """
    out = []
    i = 0
    n = len(data)

    while i < n:
        best_len = 0
        best_offset = 0

        start = max(0, i - window_size)

        # Search previous window for the longest match.
        for j in range(start, i):
            length = 0
            while (
                i + length < n
                and data[j + length] == data[i + length]
            ):
                length += 1
                if j + length >= i:
                    # Allow overlapping copies (like real LZ77)
                    break

            # Continue overlapping matches.
            while (
                length > 0 and length >= max_match
                and i + length < n
                and data[i + length]
                == data[j + (length % (i - j))]
            ):
                length += 1

            if length > best_len:
                best_len = length
                best_offset = i - j

        if best_len >= min_match:
            out.append((best_offset, best_len))
            i += best_len
        else:
            out.append((0, data[i]))
            i += 1

    return out


def lz_decode(tokens):
    """
    Decompress token stream produced by lz_encode().
    """
    out = []

    for offset, value in tokens:
        if offset == 0:
            out.append(value)
        else:
            for _ in range(value):
                out.append(out[-offset])

    return out



if __name__ == '__main__':
    do = main()
    compressed = lz_encode(do, window_size=32, max_match=8)
    print(len(compressed))
    